"use client";

import { useRef, useState, useEffect, useCallback } from "react";

interface ProgressiveBlurProps {
  className?: string;
  backgroundColor?: string;
  position?: "top" | "bottom";
  height?: string;
  blurAmount?: string;
}

const ProgressiveBlur = ({
  className = "",
  backgroundColor = "#f5f4f3",
  position = "top",
  height = "150px",
  blurAmount = "4px",
}: ProgressiveBlurProps) => {
  const isTop = position === "top";
  const containerRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLElement | null>(null);
  const [scrollProgress, setScrollProgress] = useState(isTop ? 0 : 1);

  const findScrollParent = useCallback((el: HTMLElement | null) => {
    if (!el) return null;
    let parent = el.parentElement;
    while (parent) {
      const style = window.getComputedStyle(parent);
      if (
        style.overflow === "auto" ||
        style.overflow === "scroll" ||
        style.overflowY === "auto" ||
        style.overflowY === "scroll"
      ) {
        return parent;
      }
      parent = parent.parentElement;
    }
    return document.documentElement;
  }, []);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const scrollEl = findScrollParent(container);
    scrollRef.current = scrollEl;

    const handleScroll = () => {
      if (!container || !scrollEl) return;

      const containerRect = container.getBoundingClientRect();
      const scrollElRect =
        scrollEl === document.documentElement
          ? { top: 0, height: window.innerHeight }
          : scrollEl.getBoundingClientRect();

      const overlayTop = containerRect.top - scrollElRect.top;
      const overlayHeight = containerRect.height;
      const scrollTop =
        scrollEl === document.documentElement
          ? window.scrollY
          : scrollEl.scrollTop;
      const scrollHeight =
        scrollEl === document.documentElement
          ? document.documentElement.scrollHeight
          : scrollEl.scrollHeight;
      const viewportHeight =
        scrollEl === document.documentElement
          ? window.innerHeight
          : scrollEl.clientHeight;

      const scrollRange = Math.max(scrollHeight - viewportHeight, 1);
      const contentScrolled = scrollTop / scrollRange;

      const overlayMiddle = (overlayTop + overlayHeight / 2) / scrollRange;
      const distance = Math.abs(contentScrolled - overlayMiddle);

      const maxDistance = 0.3;
      const progress = Math.min(distance / maxDistance, 1);

      setScrollProgress(progress);
    };

    scrollEl.addEventListener("scroll", handleScroll, { passive: true });
    handleScroll();

    return () => {
      scrollEl.removeEventListener("scroll", handleScroll);
    };
  }, [findScrollParent]);

  const maskOpacity = scrollProgress;

  return (
    <div
      ref={containerRef}
      className={`pointer-events-none absolute left-0 w-full select-none ${className}`}
      style={{
        [isTop ? "top" : "bottom"]: 0,
        height,
      }}
    >
      <div
        className="absolute inset-0"
        style={{
          WebkitBackdropFilter: `blur(${blurAmount})`,
          WebkitUserSelect: "none",
          backdropFilter: `blur(${blurAmount})`,
          WebkitMaskImage: isTop
            ? `linear-gradient(to bottom, rgba(0,0,0,${maskOpacity}), transparent)`
            : `linear-gradient(to top, rgba(0,0,0,${maskOpacity}), transparent)`,
          maskImage: isTop
            ? `linear-gradient(to bottom, rgba(0,0,0,${maskOpacity}), transparent)`
            : `linear-gradient(to top, rgba(0,0,0,${maskOpacity}), transparent)`,
          userSelect: "none",
        }}
      />
      <div
        className="absolute inset-0"
        style={{
          background: backgroundColor,
          WebkitMaskImage: isTop
            ? "linear-gradient(to bottom, black, transparent)"
            : "linear-gradient(to top, black, transparent)",
          maskImage: isTop
            ? "linear-gradient(to bottom, black, transparent)"
            : "linear-gradient(to top, black, transparent)",
          userSelect: "none",
        }}
      />
    </div>
  );
};

export { ProgressiveBlur };

